optimized_federated_query:
# Smart Federated Query with UNION for Multiple Class Interpretations
# Each UNION branch uses different endpoints or predicates

SELECT DISTINCT ?anylocation ?artist ?location ?locationName ?name ?news ?nytLocation
WHERE {
  # Scenario 1: ?artist=MusicArtist, ?name=Literal, ?locationName=Feature, ?anylocation=Literal, ?location=Feature, ?nytLocation=Concept
  {
    SERVICE <http://localhost:8894/sparql/> {
      ?artist <http://xmlns.com/foaf/0.1/name> ?name . # ?artist:MusicArtist, ?name:Literal
      ?artist <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://purl.org/ontology/mo/MusicArtist> .
      ?artist <http://xmlns.com/foaf/0.1/based_near> ?location .
    }
    SERVICE <http://localhost:8897/sparql/> {
      ?location <http://www.geonames.org/ontology#parentFeature> ?locationName . # ?location:Feature, ?locationName:Feature
      ?locationName <http://www.geonames.org/ontology#name> ?anylocation . # ?locationName:Feature, ?anylocation:Literal
      ?locationName <http://www.geonames.org/ontology#name> "Islamic Republic of Afghanistan" . # ?locationName:Feature
      ?nytLocation <http://www.w3.org/2002/07/owl#sameAs> ?location . # ?nytLocation:Concept, ?location:Feature
      ?nytLocation <http://data.nytimes.com/elements/topicPage> ?news .
    }
  }

  UNION

  # Scenario 2: ?artist=MusicArtist, ?name=Literal, ?locationName=Feature, ?anylocation=Literal, ?location=Drug, ?nytLocation=Drug
  {
    SERVICE <http://localhost:8894/sparql/> {
      ?artist <http://xmlns.com/foaf/0.1/name> ?name . # ?artist:MusicArtist, ?name:Literal
      ?artist <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> <http://purl.org/ontology/mo/MusicArtist> .
      ?artist <http://xmlns.com/foaf/0.1/based_near> ?location .
    }
    SERVICE <http://localhost:8895/sparql/> {
      ?nytLocation <http://www.w3.org/2002/07/owl#sameAs> ?location . # ?nytLocation:Drug, ?location:Drug
    }
    SERVICE <http://localhost:8897/sparql/> {
      ?location <http://www.geonames.org/ontology#parentFeature> ?locationName . # ?location:Feature, ?locationName:Feature
      ?locationName <http://www.geonames.org/ontology#name> ?anylocation . # ?locationName:Feature, ?anylocation:Literal
      ?locationName <http://www.geonames.org/ontology#name> "Islamic Republic of Afghanistan" . # ?locationName:Feature
      ?nytLocation <http://data.nytimes.com/elements/topicPage> ?news .
    }
  }
}
LIMIT 1000
